  overflow: hidden;
  background: var(--card-background-color);
  display: grid;
}

.compact-week-row {
  display: grid;
  gap: 4px;
  align-items: start;
  padding: 8px 10px;
  border-bottom: 1px solid var(--divider-color);
  font-size: 0.83rem;
  line-height: 1.25;
}

.compact-week-row:last-child {
  border-bottom: none;
}

.compact-week-row.left-marked {
  border-left: 4px solid var(--primary-text-color);
  padding-left: 6px;
}

.compact-week-row.current {
  font-weight: 700;
}

.compact-top {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 8px;
}

.compact-week {
  color: var(--secondary-text-color);
  min-width: 0;
  overflow-wrap: anywhere;
}

.compact-date {
  font-style: normal;
}

.compact-context {
  font-style: italic;
}

.compact-week-row.current .compact-week {
  color: var(--primary-text-color);
}

.compact-assignee {
  font-weight: 700;
  font-size: 0.9rem;
  line-height: 1.2;
}

.compact-assignee.striked {
  text-decoration: line-through;
  text-decoration-thickness: 1.5px;
}

.compact-status {
  border: 1px solid var(--divider-color);
  border-radius: 999px;
  padding: 2px 8px;
  text-transform: uppercase;
  font-size: 0.72rem;
  white-space: nowrap;
}

.compact-week-row.done .compact-status {
  color: var(--success-color, #4caf50);
}

.compact-week-row.missed .compact-status {
  color: var(--warning-color, #f57c00);
}

.compact-note {
  color: var(--secondary-text-color);
  font-size: 0.78rem;
  font-style: italic;
  text-align: left;
}

.week-row.current {
  border-left: 4px solid var(--primary-color);

