          font-weight: 700;
        }

        .notification-list {
          margin-top: -2px;
        }

        .history-panel {
          gap: 8px;
        }

        .history-slot-list,
        .history-event-list {
          list-style: none;
          margin: 0;
          padding: 0;
          display: grid;
          gap: 8px;
        }

        .history-slot-row,
        .history-event-row {
          border: 1px solid var(--divider-color);
          border-radius: 10px;
          padding: 8px 10px;
          display: grid;
          gap: 4px;
          background: var(--card-background-color);
        }

        .history-slot-top,
        .history-event-top {
          display: flex;
          align-items: center;
          justify-content: space-between;
          gap: 8px;
        }

        .history-slot-label,
        .history-event-summary {
          font-weight: 600;
          min-width: 0;
        }

        .slot-state {
          border: 1px solid var(--divider-color);
          border-radius: 999px;
          padding: 2px 8px;
          font-size: 0.72rem;
          text-transform: uppercase;
          letter-spacing: 0.03em;
          white-space: nowrap;
        }

        .slot-state.sent,
        .slot-state.test_redirected,
        .slot-state.not_required {
          color: var(--success-color, #4caf50);
          border-color: color-mix(in srgb, var(--success-color, #4caf50) 45%, var(--divider-color));
        }

        .slot-state.scheduled,
        .slot-state.no_data {
          color: var(--secondary-text-color);
        }

        .slot-state.failed,
        .slot-state.skipped,
        .slot-state.suppressed,
        .slot-state.missing {
          color: var(--warning-color, #f57c00);
          border-color: color-mix(in srgb, var(--warning-color, #f57c00) 45%, var(--divider-color));
        }

        .history-slot-detail,
        .history-slot-time,
        .history-event-action,
        .history-event-reason,
        .history-event-time {
          color: var(--secondary-text-color);
          font-size: 0.8rem;
        }

        .history-event-action {
          text-transform: uppercase;
          letter-spacing: 0.03em;
          font-size: 0.72rem;
        }

        .history-modal {
          max-height: min(85vh, 680px);
          overflow-y: auto;
        }

        .shift-status-row {
          display: flex;
          align-items: center;
          gap: 8px;
          flex-wrap: wrap;
        }

        .shift-assignee-label {
          color: var(--secondary-text-color);
          font-size: 0.88rem;
        }

        .shift-status-row strong {
          font-size: 0.95rem;
        }

        .shift-context {
          border: var(--ha-border-width-sm, 1px) solid var(--outline-color, var(--divider-color));
          border-radius: var(--ha-border-radius-lg, 12px);
          padding: var(--ha-space-3, 12px);
          background: rgba(var(--rgb-primary-text-color, 33, 33, 33), 0.03);
          display: grid;
          gap: var(--ha-space-1, 4px);
